#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    vector<int> pos, non_pos;
    for(int i = 0; i < n; i++){
        if(nums[i] > 0) pos.push_back(nums[i]);
        else non_pos.push_back(nums[i]);
    }
    for(int i = 0; i < pos.size(); i++) cout << pos[i] << ' ';
    for(int i = 0; i < non_pos.size(); i++) cout << non_pos[i] << ' ';
    return 0;
}
